/***css progress***/
#progress {
  position: relative;
  margin-bottom: 30px;
}
#progress-bar {
  position: absolute;
  background: #0052C2;
  height: 5px;
  width: 0%;
  top: 50%;
  left: 0;
}
#progress-num {
  margin: 0;
  padding: 0;
  list-style: none;
  display: flex;
  justify-content: space-between;
}
#progress-num::before {
  content: "";
  background-color: #0052C2;
  position: absolute;
  top: 50%;
  height: 2px;
  width: 100%;
  z-index: 1;
}
#progress-num .step {
  border: 2px solid #0052C2;
  border-radius: 100%;
  width: 40px;
  height: 40px;
  line-height: 34px;
  text-align: center;
  background-color: #F2F8FE;
  font-size: 1rem;  
  position: relative;
  z-index: 1;
}
#progress-num .active {
  border-color: #0052C2;
  background-color: #0052C2;
  color: #fff;
}
/***endProgress**/

